<template>
	<div id="mapCon">
		<h2 class="h-title">Ķ«Īń«ŚĶĘØń”╗ÕÆīķØóń¦» calculatedLengthAndArea</h2>
		<div id="menu">
			<label>Geometry type &nbsp;</label>
			<el-select v-model="typeValue" placeholder="Ķ»ĘķĆēµŗ®" @change="typeChange">
				<el-option value="length" label="Length"></el-option>
				<el-option value="area" label="Area"></el-option>
			</el-select>
			<el-checkbox v-model="geodesic">use geodesic measures</el-checkbox>
		</div>
		<!-- <el-button type="primary" @click="addInteraction">µĄŗĶĘØµĄŗķØó</el-button> -->
		<div id="map" class="map-x"></div>
	</div>
</template>
<script>
import 'ol/ol.css';
import { Map, View } from 'ol';
import { unByKey } from 'ol/Observable';
import { getArea, getLength } from 'ol/sphere';
import { Heatmap as HeatmapLayer, Tile as TileLayer } from 'ol/layer';
import XYZ from 'ol/source/XYZ';
import VectorLayer from 'ol/layer/Vector';
import { Vector as VectorSource } from 'ol/source';
import { Polygon, LineString } from 'ol/geom';
import { Style, Circle as CircleStyle, Icon, Fill, RegularShape, Stroke, Text } from 'ol/style';
import Overlay from 'ol/Overlay';
import { Draw } from 'ol/interaction';
export default {
	data() {
		return {
			map: null,
			source: null,
			vector: null,
			draw: null,
			// ÕĮōÕēŹń╗śÕłČńÜäĶ”üń┤Ā’╝łCurrently drawn feature.’╝ē
			sketch: null,
			// ÕĖ«ÕŖ®µÅÉńż║µĪåÕ»╣Ķ▒Ī’╝łThe help tooltip element.’╝ē
			helpTooltipElement: null,
			// ÕĖ«ÕŖ®µÅÉńż║µĪåµśŠńż║ńÜäõ┐Īµü»’╝łOverlay to show the help messages.’╝ē
			helpTooltip: '',
			// µĄŗķćÅÕĘźÕģĘµÅÉńż║µĪåÕ»╣Ķ▒Ī’╝łThe measure tooltip element. ’╝ē
			measureTooltipElement: null,
			// µĄŗķćÅÕĘźÕģĘµÅÉńż║µĪåµśŠńż║ńÜäõ┐Īµü»’╝łOverlay to show the measurement.’╝ē
			measureTooltip: '',
			// ÕĮōńö©µłĘµŁŻÕ£©ń╗śÕłČÕżÜĶŠ╣ÕĮóµŚČńÜäµÅÉńż║õ┐Īµü»µ¢ćµ£¼
			continuePolygonMsg: 'Click to continue drawing the polygon',
			// ÕĮōńö©µłĘµŁŻÕ£©ń╗śÕłČń║┐µŚČńÜäµÅÉńż║õ┐Īµü»µ¢ćµ£¼
			continueLineMsg: 'Click to continue drawing the line',
			// µĄŗķćÅń▒╗Õ×ŗ
			typeValue: 'length',
			// µĄŗÕ£░ÕŁ”µ¢╣Õ╝Å
			geodesic: false
		};
	},
	mounted() {
		this.initMap();
		this.createHelpTooltip();
		this.createMeasureTooltip();
		this.addVectorLayer();
		this.addInteraction();
	},
	methods: {
		initMap() {
			this.map = new Map({
				target: 'map',
				view: new View({
					center: [0, 0], //Õ£░ÕøŠÕłØÕ¦ŗõĖŁÕ┐āńé╣
					zoom: 4 //Õ£░ÕøŠÕłØÕ¦ŗµśŠńż║ń║¦Õł½
				}),
				layers: [
					new TileLayer({
						title: 'Õż®Õ£░ÕøŠń¤óķćÅÕøŠÕ▒é',
						source: new XYZ({
							url: 'http://t0.tianditu.com/DataServer?T=vec_w&x={x}&y={y}&l={z}&tk=49d0c416ba07ffa62dbf768c6f733645',
							wrapX: false
						})
					}),
					new TileLayer({
						title: 'Õż®Õ£░ÕøŠń¤óķćÅµ│©Ķ«░ÕøŠÕ▒é',
						source: new XYZ({
							url: 'http://t0.tianditu.com/DataServer?T=cva_w&x={x}&y={y}&l={z}&tk=49d0c416ba07ffa62dbf768c6f733645',
							wrapX: false
						})
					})
				]
			});
		},
		/**
		 * @description: ÕłøÕ╗║õĖĆõĖ¬µ¢░ńÜäÕĖ«ÕŖ®µÅÉńż║µĪå
		 * @return {*}
		 */
		createHelpTooltip() {
			if (this.helpTooltipElement) {
				this.helpTooltipElement.parentNode.removeChild(this.helpTooltipElement);
			}
			this.helpTooltipElement = document.createElement('div');
			this.helpTooltipElement.className = 'tooltip hidden';
			this.helpTooltip = new Overlay({
				element: this.helpTooltipElement,
				offset: [15, 0],
				positioning: 'center-left'
			});
			this.map.addOverlay(this.helpTooltip);
		},
		/**
		 * @description: ÕłøÕ╗║õĖĆõĖ¬µ¢░ńÜäµĄŗķćÅÕĘźÕģĘµÅÉńż║µĪå’╝łtooltip’╝ē
		 * @return {*}
		 */
		createMeasureTooltip() {
			if (this.measureTooltipElement) {
				this.measureTooltipElement.parentNode.removeChild(this.measureTooltipElement);
			}
			this.measureTooltipElement = document.createElement('div');
			this.measureTooltipElement.className = 'tooltip tooltip-measure';
			this.measureTooltip = new Overlay({
				element: this.measureTooltipElement,
				offset: [0, -15],
				positioning: 'bottom-center'
			});
			this.map.addOverlay(this.measureTooltip);
		},
		/**
		 * @description: ÕŖĀĶĮĮµĄŗķćÅńÜäń╗śÕłČń¤óķćÅÕ▒é
		 * @return {*}
		 */
		addVectorLayer() {
			this.source = new VectorSource({});
			this.vector = new VectorLayer({
				source: this.source,
				style: new Style({
					fill: new Fill({
						color: 'rgba(255, 255, 255, 0.2)' //ÕĪ½Õģģķó£Ķē▓
					}),
					stroke: new Stroke({
						color: '#ffcc33', //ĶŠ╣µĪåķó£Ķē▓
						width: 2 // ĶŠ╣µĪåÕ«ĮÕ║”
					}),
					image: new CircleStyle({
						radius: 7,
						fill: new Fill({
							color: '#ffcc33'
						})
					})
				})
			});
			this.map.addLayer(this.vector);
			// Õ£░ÕøŠÕ«╣ÕÖ©ń╗æÕ«Üķ╝ĀµĀćń¦╗ÕŖ©õ║ŗõ╗Č’╝īÕŖ©µĆüµśŠńż║ÕĖ«ÕŖ®µÅÉńż║µĪåÕåģÕ«╣
			this.map.on('pointermove', this.pointerMoveHandler);
			//Õ£░ÕøŠń╗æÕ«Üķ╝ĀµĀćń¦╗Õć║õ║ŗõ╗Č’╝īķ╝ĀµĀćń¦╗Õć║µŚČõĖ║ÕĖ«ÕŖ®µÅÉńż║µĪåĶ«ŠńĮ«ķÜÉĶŚÅµĀĘÕ╝Å
			this.map.getViewport().addEventListener('mouseout', () => {
				this.helpTooltipElement.classList.add('hidden');
			});
		},
		/**
		 * @description: ķ╝ĀµĀćń¦╗ÕŖ©õ║ŗõ╗Č
		 * @return {*}
		 */
		pointerMoveHandler(evt) {
			if (evt.dragging) {
				return;
			}
			/** @type {string} */
			let helpMsg = 'Click to start drawing'; //ÕĮōÕēŹķ╗śĶ«żµÅÉńż║õ┐Īµü»
			//Õłżµ¢Łń╗śÕłČÕćĀõĮĢń▒╗Õ×ŗĶ«ŠńĮ«ńøĖÕ║öńÜäÕĖ«ÕŖ®µÅÉńż║õ┐Īµü»
			if (this.sketch) {
				var geom = this.sketch.getGeometry();
				if (geom instanceof Polygon) {
					//ń╗śÕłČÕżÜĶŠ╣ÕĮóµŚČµÅÉńż║ńøĖÕ║öÕåģÕ«╣
					helpMsg = this.continuePolygonMsg;
				} else if (geom instanceof LineString) {
					//ń╗śÕłČń║┐µŚČµÅÉńż║ńøĖÕ║öÕåģÕ«╣
					helpMsg = this.continueLineMsg;
				}
			}
			//Õ░åµÅÉńż║õ┐Īµü»Ķ«ŠńĮ«Õł░Õ»╣Ķ»ØµĪåõĖŁµśŠńż║
			this.helpTooltipElement.innerHTML = helpMsg;
			//Ķ«ŠńĮ«ÕĖ«ÕŖ®µÅÉńż║µĪåńÜäõĮŹńĮ«
			this.helpTooltip.setPosition(evt.coordinate);
			// ń¦╗ķÖżÕĖ«ÕŖ®µÅÉńż║µĪåńÜäķÜÉĶŚÅµĀĘÕ╝ÅĶ┐øĶĪīµśŠńż║
			this.helpTooltipElement.classList.remove('hidden');
		},
		/**
		 * @description: ÕŖĀĶĮĮõ║żõ║Æń╗śÕłČµÄ¦õ╗Č
		 * @return {*}
		 */
		addInteraction() {
			let type = this.typeValue == 'area' ? 'Polygon' : 'LineString';
			this.draw = new Draw({
				source: this.source,
				type: type,
				style: new Style({
					fill: new Fill({
						color: 'rgba(255, 255, 255, 0.2)'
					}),
					stroke: new Stroke({
						color: 'rgba(0, 0, 0, 0.5)',
						lineDash: [10, 10],
						width: 2
					}),
					image: new CircleStyle({
						radius: 5,
						stroke: new Stroke({
							color: 'rgba(0, 0, 0, 0.7)'
						}),
						fill: new Fill({
							color: 'rgba(255, 255, 255, 0.2)'
						})
					})
				})
			});
			let listener;
			// ń╗æÕ«Üõ║żõ║Æń╗śÕłČÕĘźÕģĘÕ╝ĆÕ¦ŗń╗śÕłČńÜäõ║ŗõ╗Č
			this.draw.on(
				'drawstart',
				(evt) => {
					// set sketch
					this.sketch = evt.feature; //ń╗śÕłČńÜäĶ”üń┤Ā

					/** @type {ol.Coordinate|undefined} */
					var tooltipCoord = evt.coordinate; // ń╗śÕłČńÜäÕØÉµĀć
					//ń╗æÕ«Üchangeõ║ŗõ╗Č’╝īµĀ╣µŹ«ń╗śÕłČÕćĀõĮĢń▒╗Õ×ŗÕŠŚÕł░µĄŗķćÅķĢ┐Õ║”ÕĆ╝µł¢ķØóń¦»ÕĆ╝’╝īÕ╣ČÕ░åÕģČĶ«ŠńĮ«Õł░µĄŗķćÅÕĘźÕģĘµÅÉńż║µĪåõĖŁµśŠńż║
					listener = this.sketch.getGeometry().on('change', (evt) => {
						var geom = evt.target; //ń╗śÕłČÕćĀõĮĢĶ”üń┤Ā
						var output;
						if (geom instanceof Polygon) {
							output = this.formatArea(/** @type {ol.geom.Polygon} */ (geom)); //ķØóń¦»ÕĆ╝
							tooltipCoord = geom.getInteriorPoint().getCoordinates(); //ÕØÉµĀć
						} else if (geom instanceof LineString) {
							output = this.formatLength(/** @type {ol.geom.LineString} */ (geom)); //ķĢ┐Õ║”ÕĆ╝
							tooltipCoord = geom.getLastCoordinate(); //ÕØÉµĀć
						}
						this.measureTooltipElement.innerHTML = output; //Õ░åµĄŗķćÅÕĆ╝Ķ«ŠńĮ«Õł░µĄŗķćÅÕĘźÕģĘµÅÉńż║µĪåõĖŁµśŠńż║
						this.measureTooltip.setPosition(tooltipCoord); //Ķ«ŠńĮ«µĄŗķćÅÕĘźÕģĘµÅÉńż║µĪåńÜäµśŠńż║õĮŹńĮ«
					});
				},
				this
			);
			// ń╗æÕ«Üõ║żõ║Æń╗śÕłČÕĘźÕģĘń╗ōµØ¤ń╗śÕłČńÜäõ║ŗõ╗Č
			this.draw.on(
				'drawend',
				(evt) => {
					this.measureTooltipElement.className = 'tooltip tooltip-static'; //Ķ«ŠńĮ«µĄŗķćÅµÅÉńż║µĪåńÜäµĀĘÕ╝Å
					this.measureTooltip.setOffset([0, -7]);
					// unset sketch
					this.sketch = null; //ńĮ«ń®║ÕĮōÕēŹń╗śÕłČńÜäĶ”üń┤ĀÕ»╣Ķ▒Ī
					// unset tooltip so that a new one can be created
					this.measureTooltipElement = null; //ńĮ«ń®║µĄŗķćÅÕĘźÕģĘµÅÉńż║µĪåÕ»╣Ķ▒Ī
					this.createMeasureTooltip(); //ķćŹµ¢░ÕłøÕ╗║õĖĆõĖ¬µĄŗĶ»ĢÕĘźÕģĘµÅÉńż║µĪåµśŠńż║ń╗ōµ×£
					unByKey(listener);
				},
				this
			);
			this.map.addInteraction(this.draw);
		},
		/**
		 * @description: ńö©µłĘÕłćµŹóķĆēµŗ®µĄŗķćÅń▒╗Õ×ŗ’╝łķĢ┐Õ║”/ķØóń¦»’╝ē
		 * @return {*}
		 */
		typeChange() {
			this.map.removeInteraction(this.draw); //ń¦╗ķÖżń╗śÕłČÕøŠÕĮóõ║żõ║Æ
			this.addInteraction(); //µĘ╗ÕŖĀń╗śÕøŠĶ┐øĶĪīµĄŗķćÅ
		},
		/**
		 * @description: µĄŗķćÅķĢ┐Õ║”ĶŠōÕć║
		 * @param {*} line
		 * @return {*}
		 */
		formatLength(line) {
			var length;
			//ĶŗźõĮ┐ńö©µĄŗÕ£░ÕŁ”µ¢╣µ│ĢµĄŗķćÅ
			if (this.geodesic) {
				var sourceProj = this.map.getView().getProjection(); //Õ£░ÕøŠµĢ░µŹ«µ║ÉµŖĢÕĮ▒ÕØÉµĀćń│╗
				length = getLength(line, { projection: sourceProj, radius: 6378137 });
			} else {
				length = Math.round(line.getLength() * 100) / 100; //ńø┤µÄźÕŠŚÕł░ń║┐ńÜäķĢ┐Õ║”
			}
			var output;
			if (length > 100) {
				output = Math.round((length / 1000) * 100) / 100 + ' ' + 'km'; //µŹóń«ŚµłÉKMÕŹĢõĮŹ
			} else {
				output = Math.round(length * 100) / 100 + ' ' + 'm'; //mõĖ║ÕŹĢõĮŹ
			}
			return output; //Ķ┐öÕø×ń║┐ńÜäķĢ┐Õ║”
		},
		/**
		 * @description: µĄŗķćÅķØóń¦»ĶŠōÕć║
		 * @param {*} polygon
		 * @return {*}
		 */
		formatArea(polygon) {
			var area;
			if (this.geodesic) {
				//ĶŗźõĮ┐ńö©µĄŗÕ£░ÕŁ”µ¢╣µ│ĢµĄŗķćÅ
				var sourceProj = this.map.getView().getProjection(); //Õ£░ÕøŠµĢ░µŹ«µ║ÉµŖĢÕĮ▒ÕØÉµĀćń│╗
				var geom = /** @type {ol.geom.Polygon} */ (
					polygon.clone().transform(sourceProj, 'EPSG:4326')
				); //Õ░åÕżÜĶŠ╣ÕĮóĶ”üń┤ĀÕØÉµĀćń│╗µŖĢÕĮ▒õĖ║EPSG:4326
				area = Math.abs(getArea(geom, { projection: sourceProj, radius: 6378137 })); //ĶÄĘÕÅ¢ķØóń¦»
			} else {
				area = polygon.getArea(); //ńø┤µÄźĶÄĘÕÅ¢ÕżÜĶŠ╣ÕĮóńÜäķØóń¦»
			}
			var output;
			if (area > 10000) {
				output = Math.round((area / 1000000) * 100) / 100 + ' ' + 'km<sup>2</sup>'; //µŹóń«ŚµłÉKMÕŹĢõĮŹ
			} else {
				output = Math.round(area * 100) / 100 + ' ' + 'm<sup>2</sup>'; //mõĖ║ÕŹĢõĮŹ
			}
			return output; //Ķ┐öÕø×ÕżÜĶŠ╣ÕĮóńÜäķØóń¦»
		}
	}
};
</script>
<style scoped>
#mapCon {
	width: 100%;
	height: 95%;
	/* position: absolute; */
}

#menu {
	margin:0 auto;
    text-align: center;
}

.checkbox {
	left: 20px;
}
/**
        * µÅÉńż║µĪåńÜäµĀĘÕ╝Åõ┐Īµü»
        */
::v-deep .tooltip {
	position: relative;
	background: rgba(0, 0, 0, 0.5);
	border-radius: 4px;
	color: white;
	padding: 4px 8px;
	opacity: 0.7;
	white-space: nowrap;
}

::v-deep .tooltip-measure {
	opacity: 1;
	font-weight: bold;
